func robHelper(nums []int, index int) int {
	if index >= len(nums) {
		return 0
	}
	robCurrent := nums[index] + robHelper(nums, index+2)
	skipCurrent := robHelper(nums, index+1)
	if robCurrent > skipCurrent {
		return robCurrent
	}
	return skipCurrent
}

